import{_ as e,o,c as t,ag as d}from"./chunks/framework-C5-Jzrz4.js";const a=JSON.parse('{"title":"组件介绍","description":"基于真实导出入口的组件体系与 packages 归类","frontmatter":{"title":"组件介绍","description":"基于真实导出入口的组件体系与 packages 归类","lastUpdated":true},"headers":[],"relativePath":"scripts/components/introduction.md","filePath":"scripts/components/introduction.md","lastUpdated":null}');const c=e({name:"scripts/components/introduction.md"},[["render",function(e,a,c,i,n,r){return o(),t("div",null,[...a[0]||(a[0]=[d('<h1 id="组件介绍" tabindex="-1">组件介绍 <a class="header-anchor" href="#组件介绍" aria-label="Permalink to &quot;组件介绍&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本页只基于真实导出入口和源码职责整理组件体系，避免把工具库、类型库误写为组件文档。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>组件能力归类</li><li><code>packages</code> 到 <code>apps/web-antd</code> 的接入关系理解</li><li>文档阅读路径选择</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>packages/*/package.json</code></li><li><code>packages/effects/common-ui/src/index.ts</code></li><li><code>packages/@core/ui-kit/*/src/index.ts</code></li><li><code>apps/web-antd/src/components/*</code></li><li><code>apps/web-antd/src/adapter/*</code></li></ul><h2 id="packages-归类清单" tabindex="-1">packages 归类清单 <a class="header-anchor" href="#packages-归类清单" aria-label="Permalink to &quot;packages 归类清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>分类</th><th>包/目录</th><th>说明</th></tr></thead><tbody><tr><td>UI 组件或组件能力</td><td><code>@vben/common-ui</code>、<code>@vben-core/shadcn-ui</code></td><td>通用组件、基础原子组件</td></tr><tr><td>场景页面/应用层 UI</td><td><code>packages/effects/common-ui/src/ui</code></td><td>关于、认证、仪表盘、个人中心、兜底页等场景模块</td></tr><tr><td>插件/集成能力</td><td><code>@vben/plugins</code></td><td>图表、表格、动效等插件型能力</td></tr><tr><td>布局能力</td><td><code>@vben-core/layout-ui</code>、<code>@vben/layouts</code></td><td>底层布局容器与组合布局实现</td></tr><tr><td>表单能力</td><td><code>@vben-core/form-ui</code></td><td><code>setupVbenForm</code>、<code>useVbenForm</code>、Schema 与规则系统</td></tr><tr><td>菜单/标签页/弹窗交互能力</td><td><code>@vben-core/menu-ui</code>、<code>@vben-core/tabs-ui</code>、<code>@vben-core/popup-ui</code></td><td>菜单、tabbar、modal/drawer/alert</td></tr><tr><td>工具库</td><td><code>@vben/utils</code>、<code>@vben/request</code>、<code>@vben/hooks</code>、<code>@vben/access</code>、<code>@vben/icons</code></td><td>不属于组件展示主体</td></tr><tr><td>类型定义</td><td><code>@vben/types</code>、<code>@vben-core/typings</code></td><td>类型声明与协议定义</td></tr><tr><td>基础能力</td><td><code>@vben/constants</code>、<code>@vben/locales</code>、<code>@vben/preferences</code>、<code>@vben/stores</code>、<code>@vben/styles</code>、<code>@vben-core/design</code>、<code>@vben-core/shared</code>、<code>@vben-core/composables</code></td><td>常量、状态、样式、共享逻辑等底座</td></tr></tbody></table><h2 id="组件体系阅读入口" tabindex="-1">组件体系阅读入口 <a class="header-anchor" href="#组件体系阅读入口" aria-label="Permalink to &quot;组件体系阅读入口&quot;">​</a></h2><ul><li>包级聚合： <ul><li><a href="./common-ui/vben-common-ui">vben-common-ui</a></li><li><a href="./common-ui/scene-ui">scene-ui</a></li><li><a href="./layout-ui/vben-layout-system">vben-layout-system</a></li><li><a href="./common-ui/vben-plugins">vben-plugins</a></li></ul></li><li>交互核心： <ul><li><a href="./common-ui/vben-form">vben-form</a></li><li><a href="./common-ui/vben-menu">vben-menu</a></li><li><a href="./common-ui/vben-tabs">vben-tabs</a></li><li><a href="./common-ui/vben-modal">vben-modal</a></li><li><a href="./common-ui/vben-drawer">vben-drawer</a></li><li><a href="./common-ui/vben-alert">vben-alert</a></li></ul></li><li>应用层组件： <ul><li><a href="./应用层组件体系">应用层组件体系</a></li></ul></li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>先判断能力属于“包级能力”还是“应用层业务组件”，再落文档位置。</li><li><code>apps/web-antd/src/components</code> 中的组件主要服务业务页面与适配器，不等于可跨应用发布的组件包。</li><li>若某模块没有稳定导出入口，只在内部调用，不应在组件文档中当作公开 API 承诺。</li></ul>',13)])])}]]);export{a as __pageData,c as default};
